const crypto = require('crypto');

const headers = Object.keys($items("Webhook (Array Snapshot)1")[0].json.headers).reduce((acc, key) => {
    acc[key.toLowerCase()] = $items("Webhook (Array Snapshot)1")[0].json.headers[key];
    return acc;
}, {});

const body = $json.body;

const received_sig = headers['x-diagnosta-signature'];
const received_ts = headers['x-diagnosta-timestamp'];

if (!received_sig || !received_ts) {
    throw new Error("SECURITY: Sin firma digital");
}

const now = Date.now();
const requestTime = parseInt(received_ts);

if (Math.abs(now - requestTime) > 300000) {
    throw new Error("SECURITY: Timestamp expirado");
}

const secret = $env["DIAGNOSTA_WEBHOOK_SECRET"];
const salt = $env["DIAGNOSTA_SALT"];

if (!secret || !salt) {
    throw new Error("SECURITY: Variables de entorno no encontradas");
}

const expected = crypto
    .createHmac('sha256', secret + salt)
    .update(received_ts)
    .digest('hex');

if (received_sig !== expected) {
    throw new Error("SECURITY: Firma invalida");
}

if (!body.snapshots || !Array.isArray(body.snapshots)) {
    throw new Error("DATA: Sin snapshots en el payload");
}

return body.snapshots.map(snapshot => {
    return {
        json: {
            ...snapshot,
            job_id: body.job_id,
            trace_id: body.job_id + "_" + snapshot.id,
            source: body.source,
            _internal: {
                verified_at: new Date().toISOString()
            }
        }
    };
});
